import React, { useContext, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';
import {
  Lightbulb, AlertTriangle, Zap, TrendingDown, Activity, ArrowRight,
} from 'lucide-react';
import { AppCtx } from '../../App';
import { fetchFindingsSummary, fetchOptimizationTrends } from '../../api/azure';
import useAdvisorIndex from '../../hooks/useAdvisorIndex';
import useOptimizationActions from '../../hooks/useOptimizationActions';
import { formatCurrency } from '../../utils/format';
import { useOptimizationHub } from '../../context/OptimizationHubContext';
import ActionLifecycle from './ActionLifecycle';
import { LoadingState, SubscriptionRequired } from '../QueryStates';

function HubKpiCard({ label, value, sub, tone = 'default', icon: Icon, onClick }) {
  const Tag = onClick ? 'button' : 'div';
  return (
    <Tag
      type={onClick ? 'button' : undefined}
      className={`hub-overview-kpi hub-overview-kpi--${tone}${onClick ? ' hub-overview-kpi--clickable' : ''}`}
      onClick={onClick}
    >
      <div className="hub-overview-kpi__icon" aria-hidden>
        <Icon size={18} />
      </div>
      <div className="hub-overview-kpi__body">
        <span className="hub-overview-kpi__label">{label}</span>
        <strong className="hub-overview-kpi__value">{value}</strong>
        {sub && <span className="hub-overview-kpi__sub">{sub}</span>}
      </div>
      {onClick && <ArrowRight size={14} className="hub-overview-kpi__chevron" aria-hidden />}
    </Tag>
  );
}

export default function OptimizationHubOverview() {
  const { subscription, billingCurrency } = useContext(AppCtx);
  const currency = billingCurrency || 'CAD';
  const { setTab } = useOptimizationHub();

  const { data: findingsSummary, isLoading: findingsLoading } = useQuery({
    queryKey: ['findings-summary', subscription],
    queryFn: () => fetchFindingsSummary({ subscription_id: subscription }),
    enabled: !!subscription,
    staleTime: 60_000,
  });

  const {
    items: advisorItems,
    indexReady: advisorReady,
    isLoading: advisorLoading,
    hasData: hasAdvisorData,
  } = useAdvisorIndex(subscription);

  const {
    summary: actionsSummary,
    total: actionsTotal,
    totalSavings: actionsSavings,
    isLoading: actionsLoading,
  } = useOptimizationActions(subscription, {});

  const { data: trends } = useQuery({
    queryKey: ['optimization-trends', subscription],
    queryFn: () => fetchOptimizationTrends({ subscription_id: subscription }),
    enabled: !!subscription,
    staleTime: 120_000,
  });

  const advisorStats = useMemo(() => {
    let high = 0;
    let savings = 0;
    for (const item of advisorItems) {
      if (item.impact === 'High') high += 1;
      savings += item.potential_savings_monthly || 0;
    }
    return { count: advisorItems.length, high, savings };
  }, [advisorItems]);

  if (!subscription) return <SubscriptionRequired />;

  if (findingsLoading || advisorLoading || actionsLoading) {
    return <LoadingState message="Loading optimization summary…" />;
  }

  const openFindings = findingsSummary?.open_findings ?? 0;
  const estSavings = findingsSummary?.total_estimated_savings_usd ?? 0;
  const highSeverity = findingsSummary?.by_severity?.HIGH ?? 0;
  const criticalSeverity = findingsSummary?.by_severity?.CRITICAL ?? 0;

  return (
    <div className="optimization-hub-panel__content hub-overview">
      <p className="hub-overview__lead">
        Engine findings, Azure Advisor, cost signals, and approved actions in one place.
        Open a tab below for details or browse inventory tables for per-resource Advisor and cost signals.
      </p>

      <div className="hub-overview-kpi-grid">
        <HubKpiCard
          label="Engine findings"
          value={openFindings.toLocaleString()}
          sub={estSavings > 0 ? `${formatCurrency(estSavings, { currency })} potential/mo` : `${highSeverity + criticalSeverity} high priority`}
          tone="findings"
          icon={AlertTriangle}
          onClick={() => setTab('recommendations')}
        />
        <HubKpiCard
          label="Azure Advisor"
          value={advisorReady ? advisorStats.count.toLocaleString() : '…'}
          sub={
            !hasAdvisorData
              ? 'Sync from Optimization center'
              : (advisorStats.high > 0
                ? `${advisorStats.high} high impact`
                : (advisorStats.savings > 0
                  ? `${formatCurrency(advisorStats.savings, { currency })}/mo potential`
                  : 'Active recommendations'))
          }
          tone="advisor"
          icon={Lightbulb}
          onClick={() => setTab('advisor')}
        />
        <HubKpiCard
          label="Optimization actions"
          value={(actionsTotal || 0).toLocaleString()}
          sub={actionsSavings > 0 ? `${formatCurrency(actionsSavings, { currency })} proposed/mo` : `${actionsSummary?.proposed ?? actionsSummary?.proposed_count ?? 0} proposed`}
          tone="actions"
          icon={Zap}
          onClick={() => setTab('actions')}
        />
        <HubKpiCard
          label="Cost signals"
          value={openFindings > 0 ? 'Per resource' : '—'}
          sub="Metric triggers in findings & drawer"
          tone="signals"
          icon={Activity}
          onClick={() => setTab('recommendations')}
        />
      </div>

      <ActionLifecycle
        counts={actionsSummary}
        inObservation={trends?.rollout?.in_observation ?? 0}
        currency={currency}
        savings={actionsSavings}
        onStepClick={(stepId) => {
          setTab(stepId === 'executing' ? 'monitor' : 'actions');
        }}
        className="hub-overview-lifecycle"
      />

      <div className="hub-overview-panels">
        <section className="hub-overview-panel">
          <div className="hub-overview-panel__head">
            <h3>Quick links</h3>
          </div>
          <ul className="hub-overview-links">
            <li><button type="button" className="hub-overview-link" onClick={() => setTab('recommendations')}>Engine recommendations</button></li>
            <li><button type="button" className="hub-overview-link" onClick={() => setTab('advisor')}>Azure Advisor by resource</button></li>
            <li><button type="button" className="hub-overview-link" onClick={() => setTab('actions')}>Review & approve actions</button></li>
            <li><button type="button" className="hub-overview-link" onClick={() => setTab('scoreboard')}>Optimization scoreboard</button></li>
            <li><Link to="/costs" className="hub-overview-link">Cost explorer</Link></li>
            <li><Link to="/admin/optimization" className="hub-overview-link">Optimization center (sync)</Link></li>
          </ul>
        </section>

        <section className="hub-overview-panel">
          <div className="hub-overview-panel__head">
            <h3>How data connects</h3>
          </div>
          <ol className="hub-overview-flow">
            <li><strong>Sync</strong> inventory, costs, and Advisor from Optimization center.</li>
            <li><strong>Analyze</strong> to generate engine findings with cost metric triggers.</li>
            <li><strong>Review</strong> findings and Advisor per resource in inventory tables.</li>
            <li><strong>Decide</strong> synthesized actions and track rollout in Scoreboard.</li>
          </ol>
        </section>

        {!hasAdvisorData && (
          <div className="hub-overview-banner" role="status">
            <TrendingDown size={16} aria-hidden />
            <span>
              Azure Advisor recommendations are empty. Run <strong>Sync Advisor</strong> in{' '}
              <Link to="/admin/optimization">Optimization center</Link> to populate inventory Advisor columns.
            </span>
          </div>
        )}
      </div>
    </div>
  );
}
